#include "RecommendationEngine.h"
uint8_t RecommendationEngine::generate(const SolarData& s,const BatteryData& b,float load,Recommendation* out,uint8_t maxOut){ uint8_t n=0; auto add=[&](const char*t){ if(n<maxOut){snprintf(out[n].text,MAX_TEXT,"%s",t); n++;}}; if(s.power>load+100)add("Good solar production detected. Consider running high-energy appliances such as washing machines or pumps now instead of later."); if(b.soc<25)add("Battery is approaching reserve capacity. Delay non-essential appliances to avoid deep discharge."); if(b.soc>90&&s.power>load)add("Excess solar energy is available. This is an ideal time to operate optional loads."); if(load>0)add("Today's solar generation is prioritized for household demand. Estimated battery autonomy is based on current consumption rate."); return n; }
